def _utc_iso():
    return datetime.now(timezone.utc).isoformat()

def _get_credential():
    return DefaultAzureCredential(exclude_interactive_browser_credential=True)

def _get_blob_service(credential):
    account_url = os.environ["STORAGE_ACCOUNT_URL"].strip()
    return BlobServiceClient(account_url=account_url, credential=credential)

def _get_cosmos_client(credential):
    endpoint = os.environ["COSMOS_ENDPOINT"].strip()
    return CosmosClient(url=endpoint, credential=credential)

def _get_cosmos_container(cosmos_client):
    db_name = os.environ["COSMOS_DATABASE"].strip()
    container_name = os.environ["COSMOS_CONTAINER"].strip()
    db = cosmos_client.create_database_if_not_exists(id=db_name)
    container = db.create_container_if_not_exists(
        id=container_name,
        partition_key=PartitionKey(path="/pk"),
        offer_throughput=400
    )
    return container

def _get_eventgrid_client(credential):
    topic_endpoint = os.environ["EVENTGRID_TOPIC_ENDPOINT"].strip()
    topic_key = os.getenv("EVENTGRID_TOPIC_KEY")
    if topic_key:
        return EventGridPublisherClient(topic_endpoint, AzureKeyCredential(topic_key))
    return EventGridPublisherClient(topic_endpoint, credential)

def _safe_decode(b: bytes):
    try:
        return b.decode("utf-8")
    except Exception:
        return None

def _process_blob_content(blob_name: str, content: bytes):
    text = _safe_decode(content)
    if text is None:
        return {
            "blobName": blob_name,
            "contentType": "binary",
            "size": len(content),
            "sha1": None,
            "lines": None,
            "words": None,
        }

    lines = text.splitlines()
    words = sum(len(line.split()) for line in lines)
    return {
        "blobName": blob_name,
        "contentType": "text/utf-8",
        "size": len(content),
        "lines": len(lines),
        "words": words,
        "preview": text[:512],
    }

def _write_result(container, result_doc: dict):
    container.upsert_item(result_doc)

def _send_notification(eventgrid_client, subject_prefix: str, result_doc: dict):
    event = {
        "id": str(uuid.uuid4()),
        "eventType": "mvp.fileProcessed",
        "subject": f"{subject_prefix}/blobs/{result_doc.get('blobName','')}",
        "eventTime": _utc_iso(),
        "dataVersion": "1.0",
        "data": {
            "id": result_doc["id"],
            "pk": result_doc["pk"],
            "blobName": result_doc.get("blobName"),
            "container": result_doc.get("container"),
            "status": result_doc.get("status"),
            "processedAt": result_doc.get("processedAt"),
            "summary": result_doc.get("summary"),
        },
    }
    eventgrid_client.send([event])

def _iter_target_blobs(blob_service: BlobServiceClient, container_name: str, prefix: str | None, max_blobs: int):
    container_client = blob_service.get_container_client(container_name)
    count = 0
    for blob in container_client.list_blobs(name_starts_with=prefix):
        yield blob.name
        count += 1
        if max_blobs and count >= max_blobs:
            break

